  ('optician-moex-00769', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '進行遮蓋－去遮蓋測試（cover-uncovertest）時，當遮蓋右眼，左眼不動；遮蓋左眼，右眼由顳側向鼻側移 動。遮眼棒從左眼移開，觀察右眼，右眼不動。根據此檢查結果，下列診斷何者正確？', '["左眼內斜視", "交替性外斜視", "右眼外斜視", "右眼外隱斜位"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
